INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2997, 24, 'Un classique indémodable !', TO_DATE('2024-05-03', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2235, 17, 'De l''ananas avec du poulet ? Une hérésie !', TO_DATE('2026-01-11', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (865, 8, 'La raclette est parfaitement fondante.', TO_DATE('2024-09-20', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1913, 10, 'Trop de légumes à mon goût.', TO_DATE('2025-09-16', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1616, 16, 'Le meilleur mélange tenders-raclette jamais goûté.', TO_DATE('2024-09-06', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1068, 21, 'Correct mais manque de sauce.', TO_DATE('2025-09-23', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (487, 17, 'Une tuerie les tenders sont super croustillants !', TO_DATE('2025-05-04', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2707, 7, 'Bonne alliance entre le saumon et le fromage.', TO_DATE('2024-12-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (209, 1, 'Rejet total : présence de brocolis non signalée.', TO_DATE('2024-01-26', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2876, 25, 'L''essence même de l''Ordre dans un plat.', TO_DATE('2024-12-24', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1296, 15, 'Le fromage fumé fait toute la différence.', TO_DATE('2024-08-11', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (529, 21, 'Un peu trop gras pour une réunion secrète.', TO_DATE('2025-11-12', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (592, 6, 'L''ananas apporte une fraîcheur surprenante.', TO_DATE('2024-09-25', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1998, 5, 'Plat généreux mais présentation à revoir.', TO_DATE('2026-02-22', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1945, 7, 'Parfait pour célébrer un nouveau grade.', TO_DATE('2025-07-02', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1913, 10, 'Une raclette digne des plus grands chevaliers. Le fromage coulait avec une grâce infinie. Honneur et saveur réunis en une seule soirée mémorable.', TO_DATE('2025-08-11', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (546, 6, 'Les tenders étaient d''une tendreté absolument transcendante. La sauce secrète de l''Ordre restera gravée dans ma mémoire pour l''éternité.', TO_DATE('2025-01-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2342, 5, 'Repas exceptionnel. Le fromage fondait à la perfection, les tenders croustillants à souhait. Un festin digne du Grand Maître lui-même.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (12, 1, 'Le banquet de l''Ordre Suprême fut à la hauteur de sa réputation. Chaque plat était une ode à la raclette. Je suis fier d''être Tenrac.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (610, 4, 'Dégustations sublimes. Les chevaliers ont honoré la tradition avec brio. La lampe à raclette ronronnait comme jamais. Soirée parfaite.', TO_DATE('2024-09-17', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (944, 21, 'La lame chauffante a fait des merveilles ce soir. Fromage doré, tenders fondants, ambiance mystique. Je ne pouvais rêver mieux.', TO_DATE('2025-10-04', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1882, 8, 'La Cène du Coulant Éternel porte bien son nom. Chaque bouchée était une révélation spirituelle fromagère. Respect à l''Ordre.', TO_DATE('2024-07-10', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1056, 19, 'Les porte-spatules ont assuré avec maestria. Service impeccable, raclette parfaite, ambiance secrète au rendez-vous. Cinq étoiles mérités.', TO_DATE('2024-04-03', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2896, 13, 'La nuit du fromage interminable fut exactement ça : interminable et délicieuse. On a raclé jusqu''à l''aube. Magnifique souvenir.', TO_DATE('2025-11-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (98, 1, 'Souper des initiés réussi à merveille. Le gril mystique n''a pas déçu. Les tenders bénis étaient à tomber. Vive l''Ordre !', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1251, 4, 'Communion parfaite autour du tender béni. L''atmosphère était solennelle et la raclette divine. Un moment de grâce pure pour tout Tenrac.', TO_DATE('2024-12-31', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1803, 16, 'La croûte dorée méritait amplement son nom ce soir. Croustillante, généreuse, parfumée. Le commandeur a validé chaque plat. Parfait.', TO_DATE('2026-03-21', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (157, 3, 'Grand Conclave réussi haut la main. Le fil fondu était interminable comme il se doit. Soirée inoubliable entre frères de l''Ordre.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (499, 12, 'Raclette somptueuse, tenders parfaitement frits, ambiance feutrée. Le Chevalier présidant a su maintenir la tradition. Très grande soirée.', TO_DATE('2025-06-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2837, 8, 'Impossible de trouver le moindre défaut. Tenders croustillants, fromage coulant, sauce maison irréprochable. L''Ordre est en bonne santé.', TO_DATE('2024-04-15', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2111, 5, 'Très bon repas dans l''ensemble. La raclette était généreuse et bien chaude. Quelques tenders un poil trop cuits mais rien de grave.', TO_DATE('2025-06-18', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (356, 4, 'Banquet de qualité, le fromage était excellent. Le service aurait pu être plus rapide mais l''ambiance compensait largement.', TO_DATE('2024-10-09', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (839, 8, 'Belle dégustation, les chevaliers ont bien travaillé. La raclette manquait légèrement de sel mais les tenders étaient excellents.', TO_DATE('2024-06-20', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (566, 6, 'Bon repas, la lampe chauffait bien. Le fromage était coulant à souhait. J''aurais aimé un peu plus de variété dans les accompagnements.', TO_DATE('2024-03-16', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (502, 10, 'Très bonne cène, l''ambiance mystique était au rendez-vous. La raclette était fondante. Dommage que le repas ait été un peu court.', TO_DATE('2025-08-04', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2377, 21, 'Bon festin des porte-spatules. Les tenders étaient savoureux. La raclette légèrement moins chaude qu''espéré mais très bonne quand même.', TO_DATE('2025-09-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2837, 8, 'Belle nuit fromagère. Le fromage était de qualité et les tenders bien assaisonnés. Ambiance un peu moins mystérieuse que d''habitude.', TO_DATE('2024-07-08', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1305, 21, 'Souper réussi, les initiés ont bien honoré la tradition. Raclette généreuse. Petit bémol sur l''organisation de la fin de soirée.', TO_DATE('2026-03-16', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2873, 19, 'Bonne communion autour du tender. Fromage coulant, ambiance chaleureuse. On aurait apprécié un dessert à la hauteur du reste.', TO_DATE('2024-10-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (248, 3, 'Festin de la croûte dorée bien réussi. Tenders croustillants et raclette fondante. Quelques minutes d''attente en trop entre les plats.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1200, 25, 'Grand conclave plaisant. Le fil fondu était long comme il faut. Légère déception sur la qualité du fromage ce soir, mais bon repas.', TO_DATE('2025-04-03', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2509, 25, 'Bonne raclette traditionnelle. Le chevalier présidant a bien géré la soirée. Les tenders dorés étaient à la hauteur des espérances.', TO_DATE('2026-02-07', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (115, 8, 'Festin du tender réussi. Sauce secrète toujours aussi mystérieuse et savoureuse. Manquait un peu de fromage à mon goût personnel.', TO_DATE('2024-07-24', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1440, 20, 'Raclette des ombres bien mystérieuse. Fromage correct, tenders bien frits. L''adresse secrète était particulièrement bien choisie ce soir.', TO_DATE('2024-05-06', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2790, 22, 'Banquet honorable. L''Ordre a maintenu son niveau de qualité habituel. Petit manque d''originalité dans les plats proposés cette fois.', TO_DATE('2025-08-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (949, 18, 'Repas correct sans être mémorable. La raclette était un peu trop froide à mon goût. Les tenders compensaient heureusement la situation.', TO_DATE('2026-03-01', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (100, 24, 'Soirée moyenne. La lampe chauffante semblait fatiguée ce soir. Fromage pas assez coulant, tenders corrects. On a vu mieux par le passé.', TO_DATE('2024-07-28', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1450, 17, 'Cène décevante. L''ambiance mystique n''était pas vraiment au rendez-vous. La raclette était banale. J''espère mieux pour le prochain repas.', TO_DATE('2025-06-15', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (486, 15, 'Festin moyen. Les porte-spatules ont manqué d''entrain. La raclette était correcte mais sans éclat particulier. Ambiance un peu terne.', TO_DATE('2025-05-14', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (45, 19, 'Nuit fromagère sans grand relief. Le fromage était acceptable mais pas exceptionnel. Les tenders étaient trop secs. Peut mieux faire.', TO_DATE('2025-01-27', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (175, 17, 'Souper passable. Le gril mystique n''a pas semblé très inspiré ce soir. Raclette correcte, tenders ordinaires. Déception relative.', TO_DATE('2025-02-07', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2038, 22, 'Communion tendue. Quelques désaccords sur la cuisson des tenders ont plombé l''ambiance. Fromage correct mais soirée en demi-teinte.', TO_DATE('2024-04-11', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (34, 1, 'La croûte n''était pas aussi dorée qu''annoncé. Repas honnête mais sans surprise. Le commandeur semblait lui-même peu convaincu.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1669, 21, 'Conclave moyen. Le fil fondu s''est cassé trop vite. Organisation perfectible. La raclette sauvait un peu les meubles heureusement.', TO_DATE('2026-03-03', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1505, 2, 'Raclette traditionnelle trop traditionnelle justement. Manque d''originalité flagrant. Tenders corrects. On attendait plus de créativité.', TO_DATE('2024-02-27', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (200, 10, 'Tender correct mais sauce secrète moins secrète que d''habitude. L''impression d''avoir déjà goûté ça. Repas sans grande surprise.', TO_DATE('2025-07-21', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (288, 1, 'Raclette des ombres trop éclairée. Manque de mystère et de fromage. Les tenders étaient trop frits. Soirée en dessous des attentes.', TO_DATE('2024-01-26', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (20, 1, 'Banquet trop long et pas assez garni. On a attendu entre chaque plat. La raclette était correcte mais l''organisation laissait à désirer.', TO_DATE('2024-01-26', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (949, 18, 'Dégustation ordinaire. Les chevaliers semblaient fatigués. Fromage moyen, tenders acceptables. Rien de transcendant ce soir malheureusement.', TO_DATE('2025-12-16', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (785, 5, 'Soirée décevante. La lampe à raclette tombait en panne toutes les dix minutes. Fromage à peine fondu, tenders froids. Vraiment dommage.', TO_DATE('2025-01-26', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1935, 9, 'Cène ratée. Le fromage était trop épais et mal cuit. Les tenders semblaient réchauffés. L''ambiance mystique était totalement absente.', TO_DATE('2025-06-01', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (219, 1, 'Festin des porte-spatules très décevant. Les spatules ont peu servi tellement il y avait peu à racler. Quantités insuffisantes pour tous.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1686, 17, 'Nuit fromagère cauchemardesque. Le fromage était dur, les tenders caoutchouteux. On a failli rompre le vœu de silence tellement c''était mauvais.', TO_DATE('2024-08-01', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1854, 21, 'Souper raté. Le gril mystique a rendu l''âme en plein milieu du repas. Repas froid, ambiance glaciale. Décevant pour un repas de l''Ordre.', TO_DATE('2024-09-28', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1898, 24, 'Communion avortée. La machine est tombée en panne. On a fini à la bougie avec du fromage tiède. Expérience à ne pas renouveler.', TO_DATE('2026-01-13', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1288, 15, 'La croûte n''était pas dorée mais carbonisée. Tenders brûlés, fromage caoutchouteux. Le commandeur lui-même a quitté la table tôt.', TO_DATE('2026-01-14', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (532, 10, 'Grand conclave raté. Le fil s''est cassé immédiatement. Fromage acheté en dernière minute et de mauvaise qualité. Grande déception.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1264, 21, 'Raclette immanquable. Fromage froid, tenders crus au centre. La lampe ne chauffait pas. Honte à l''organisateur. L''Ordre mérite mieux.', TO_DATE('2025-03-04', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2998, 24, 'Festin catastrophique. Les tenders sentaient le réchauffé. La sauce secrète était visiblement du ketchup industriel. Inadmissible.', TO_DATE('2024-06-08', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1355, 5, 'Raclette des ombres : les ombres ont tout mangé avant nous apparemment. Portions minuscules, fromage insipide. Soirée à oublier.', TO_DATE('2025-08-15', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1511, 5, 'Banquet indigne de l''Ordre. Fromage avarié, tenders oubliés dans la friteuse, machine en panne. Le Grand Maître serait consterné.', TO_DATE('2024-10-04', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1029, 16, 'Pire dégustation de ma vie de Tenrac. Tout était froid, rien n''était prêt. Les chevaliers présents étaient aussi perdus que moi.', TO_DATE('2025-07-25', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (89, 6, 'Soirée honteuse. La lampe ardente n''ardait pas du tout. Fromage industriel, tenders congelés pas décongelés. Scandale absolu.', TO_DATE('2025-12-07', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (221, 3, 'Cène du coulant éternel : rien n''a coulé. Fromage bloc, tenders caoutchouc, ambiance funèbre. Je demande réparation à l''Ordre.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2974, 22, 'Les porte-spatules ont porté des spatules inutiles. Rien à racler, rien à manger. Organisation désastreuse du début à la fin.', TO_DATE('2025-05-26', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (352, 25, 'Raclette divine, fromage coulant à la perfection. Les tenders croustillants fondaient en bouche. Soirée inoubliable digne du Grand Maître.', TO_DATE('2024-09-29', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (484, 15, 'Un festin digne des plus hauts grades de l''Ordre. Chaque bouchée était une révélation fromagère absolue. Vive les Tenracs !', TO_DATE('2025-08-31', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (720, 7, 'Fromage d''exception, tenders bénis, ambiance mystique au rendez-vous. Le Chevalier présidant a honoré la tradition avec brio.', TO_DATE('2024-09-13', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1722, 21, 'La lampe à raclette ronronnait comme jamais. Fromage doré, tenders fondants. On ne pouvait rêver meilleure soirée entre Tenracs.', TO_DATE('2026-03-19', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (717, 6, 'Festin exceptionnel. Chaque plat était une ode à la raclette sacrée. Je suis fier et rassasié d''être membre de cet Ordre.', TO_DATE('2024-11-26', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (277, 4, 'Les tenders étaient d''une tendreté absolument transcendante. La sauce secrète restera gravée dans ma mémoire pour toujours.', TO_DATE('2024-09-20', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (200, 24, 'Raclette somptueuse, ambiance feutrée et solennelle. Le fromage coulait avec une grâce infinie. Honneur et saveur réunis.', TO_DATE('2024-06-09', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1126, 8, 'Soirée parfaite de bout en bout. La machine ronronnait, le fromage coulait, les tenders craquaient. L''Ordre est en grande forme.', TO_DATE('2024-03-15', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2190, 13, 'Le Grand Chancelier lui-même aurait applaudi. Qualité irréprochable, générosité exemplaire. Un repas de légende tenracienne.', TO_DATE('2024-12-03', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (24, 1, 'Les porte-spatules ont assuré avec maestria. Service impeccable, raclette parfaite. Cinq étoiles amplement mérités ce soir.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (443, 9, 'Fromage coulant, tenders croustillants, sauce divine. L''adresse secrète était idéale. Une soirée gravée dans les annales de l''Ordre.', TO_DATE('2025-12-25', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2636, 13, 'Dégustations sublimes. Les chevaliers ont honoré la tradition avec brio. On a raclé jusqu''à l''aube avec joie et dévotion.', TO_DATE('2025-02-06', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2155, 8, 'La nuit du fromage interminable portait bien son nom. Délicieuse, généreuse, mystérieuse. Magnifique souvenir de Tenrac.', TO_DATE('2024-07-09', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (954, 4, 'Communion parfaite autour du tender béni. Fromage coulant, ambiance chaleureuse. Un moment de grâce pure et fromagère.', TO_DATE('2026-01-11', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1065, 16, 'Les Frères de la Lampe Ardente ont brillé ce soir. Tout était parfait, du fromage à l''ambiance. Je reviendrai sans hésiter.', TO_DATE('2024-10-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1671, 23, 'La croûte dorée méritait amplement son nom. Croustillante, généreuse, parfumée. Le Commandeur a validé chaque plat.', TO_DATE('2026-03-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (877, 2, 'Grand conclave réussi haut la main. Le fil fondu était interminable comme il se doit. Soirée inoubliable entre frères.', TO_DATE('2025-04-14', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (659, 9, 'Raclette traditionnelle sublimée par un fromage hors du commun. Les tenders dorés étaient à la hauteur des espérances.', TO_DATE('2025-07-01', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2749, 19, 'Impossible de trouver le moindre défaut ce soir. Tenders croustillants, fromage coulant, sauce maison irréprochable.', TO_DATE('2024-04-20', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1092, 9, 'Chaque bouchée de tender nappé de raclette était une prière silencieuse. L''Ordre sait encore recevoir. Chapeau bas.', TO_DATE('2025-12-12', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (515, 15, 'La sauce secrète de l''Ordre restera gravée dans ma mémoire. Associée aux tenders et au fromage, c''était divin.', TO_DATE('2025-08-10', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2914, 21, 'Organisation parfaite, fromage d''excellence, ambiance solennelle. La dignité du repas Tenrac était pleinement respectée.', TO_DATE('2024-12-05', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2199, 7, 'Le Maître d''entretien avait bien préparé la machine. Chauffe optimale, fromage parfait. On sent le soin apporté au rite.', TO_DATE('2025-03-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2242, 24, 'Soirée de haute tenue. Fromage affiné, tenders moelleux, sauce mystérieuse. L''adresse secrète était particulièrement bien choisie.', TO_DATE('2026-03-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1040, 2, 'On a raclé, on a fondu, on a savouré. Dans cet ordre et avec bonheur. L''Ordre Tenrac préserve un art de vivre unique.', TO_DATE('2025-03-09', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2235, 8, 'Festin royal. Le Grand Chevalier présidant a su créer une atmosphère unique. Fromage exceptionnel, tenders bénis.', TO_DATE('2024-05-25', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1446, 5, 'La raclette des ombres portait bien son nom : mystérieuse et savoureuse. Tenders parfaits, ambiance secrète réussie.', TO_DATE('2025-05-13', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1111, 2, 'Banquet de l''Ordre à la hauteur de sa réputation légendaire. Chaque plat était une ode à notre repas sacré.', TO_DATE('2026-01-14', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1450, 17, 'Le sanctuaire du tender béni a tenu toutes ses promesses. Soirée magique, fromage coulant, tenders croustillants.', TO_DATE('2025-05-30', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (290, 6, 'Repas exceptionnel servi avec solennité. La Haute Dame présidait avec grâce. Fromage et tenders en parfaite harmonie.', TO_DATE('2025-09-07', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1772, 17, 'Le cercle des fondus tranquilles portait bien son nom. Ambiance apaisée, raclette généreuse, tenders bien assaisonnés.', TO_DATE('2024-06-08', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (165, 11, 'Les gardiens de la plaque chauffante ont bien veillé ce soir. Température parfaite, fromage sublime, tenders exemplaires.', TO_DATE('2025-11-04', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (839, 8, 'La confrérie du coulant sacré a encore frappé fort. Fromage d''une fluidité divine, tenders croustillants à souhait.', TO_DATE('2024-06-30', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (216, 9, 'Les veilleurs de la croûte méritent leur titre. Croûte dorée à la perfection, fromage coulant, tenders fondants.', TO_DATE('2025-11-30', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1173, 9, 'Le phalanstère du bon fondu n''a pas menti. Fondu, tendre, savoureux. Une expérience tenracienne complète et réussie.', TO_DATE('2026-03-08', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1041, 12, 'La brigade fromagère de l''ombre a frappé fort dans l''obscurité. Fromage de caractère, tenders bien frits. Parfait.', TO_DATE('2025-08-23', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (857, 19, 'Le cénacle des fromagers errants a trouvé son chemin vers l''excellence. Très grande soirée de communion fromagère.', TO_DATE('2024-05-26', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2767, 9, 'La loge hermétique du bon fromage a livré ses secrets ce soir. Un fromage d''une qualité rarement atteinte. Bravo.', TO_DATE('2026-02-27', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (559, 9, 'Les apôtres du coulant mystérieux ont converti jusqu''au dernier sceptique. Raclette parfaite, foi en l''Ordre renforcée.', TO_DATE('2026-01-11', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1104, 19, 'La commanderie de la plaque ardente était en feu ce soir. Fromage ardent, tenders flambants, ambiance embrasée.', TO_DATE('2026-03-23', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1416, 2, 'Le conclave des chevaliers racleurs fut mémorable. Chaque chevalier a donné le meilleur de lui-même pour ce festin.', TO_DATE('2026-03-06', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (39, 1, 'Les disciples de la lampe sacrée ont illuminé cette soirée. Lumière et fromage fondus ensemble dans la perfection.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2320, 9, 'La citadelle du tender immuable a prouvé que la tradition est une force. Tenders identiques à eux-mêmes : excellents.', TO_DATE('2026-02-18', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2824, 17, 'La société du gratin perpétuel mérite son nom. Un gratin de qualité perpétuellement maintenu. Respect à l''organisation.', TO_DATE('2024-07-15', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2627, 8, 'Les porteurs de la raclette sacrée ont accompli leur mission avec honneur. Raclette livrée à destination : parfaite.', TO_DATE('2024-02-22', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (419, 12, 'Le club des initiés du tender flambé initie avec talent. Tenders flambés à merveille, fromage en apothéose finale.', TO_DATE('2024-07-31', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1722, 21, 'Les hérauts du fromage interminable ont annoncé la bonne nouvelle. Le fromage était effectivement interminable et divin.', TO_DATE('2026-03-18', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (173, 10, 'La fraternité de l''appareil mystique maîtrise ses machines. Entretien parfait, chauffe optimale, résultat exceptionnel.', TO_DATE('2025-02-13', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (109, 1, 'Le chapitre des compagnons du gril honore ses engagements. Gril parfait, fromage coulant, tenders croustillants.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (972, 20, 'L''ordre discret des palais brûlants a su ménager le suspense. Révélation fromagère en fin de soirée. Magistral.', TO_DATE('2024-05-29', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (691, 22, 'La guilde des maîtres racleurs démontre son expertise à chaque repas. Ce soir encore, la maîtrise était totale.', TO_DATE('2025-05-19', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2262, 16, 'Les éveilleurs du fromage endormi ont accompli leur mission. Le fromage s''est éveillé dans toute sa splendeur.', TO_DATE('2026-03-13', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1330, 4, 'Le bastion des tenracs de l''ouest tient bon. Qualité constante, tradition respectée, fromage excellent. Félicitations.', TO_DATE('2024-12-07', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2060, 20, 'La confrérie du tender et de l''épée tranche dans le vif du sujet. Tenders nets, fromage franc, soirée directe.', TO_DATE('2024-10-20', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (26, 14, 'Le grand atelier du fil fondu éternel n''a jamais aussi bien filé. Fromage interminable, tenders sans fin. Parfait.', TO_DATE('2024-08-23', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2596, 21, 'Repas béni des dieux fromageurs. La raclette coulait comme une rivière de bonheur. Je recommande sans la moindre réserve.', TO_DATE('2026-01-31', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2323, 13, 'La tradition Tenrac est bien vivante. Ce repas en est la preuve absolue. Fromage, tenders, amitié. Tout était réuni.', TO_DATE('2024-10-14', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1339, 12, 'Un repas qui restera dans les annales. Le Grand Maître en personne n''aurait pu faire mieux. Honneur à l''organisateur.', TO_DATE('2025-08-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (802, 11, 'Le fromage était si bon que j''ai failli trahir le secret de l''adresse. Heureusement la règle de l''Ordre m''en a empêché.', TO_DATE('2026-01-07', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2322, 4, 'Tenders d''une qualité rare, fromage d''une générosité inouïe. L''Ordre Tenrac mérite sa réputation d''excellence absolue.', TO_DATE('2024-08-25', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1690, 2, 'On a fondu de plaisir autant que le fromage. Métaphore réussie et repas réussi. Une soirée Tenrac comme on les aime.', TO_DATE('2026-02-24', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (505, 20, 'La raclette chantait sous la lampe ardente. Les tenders dansaient dans la friteuse. Une symphonie gastronomique tenracienne.', TO_DATE('2024-08-19', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1094, 21, 'Cinq étoiles sans hésiter. Le fromage, les tenders, l''ambiance, le secret, tout concourait à la perfection absolue.', TO_DATE('2025-04-23', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1831, 5, 'Raclette divine, fromage coulant à la perfection. Les tenders croustillants fondaient en bouche. Soirée inoubliable digne du Grand Maître.', TO_DATE('2026-01-20', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (297, 1, 'Un festin digne des plus hauts grades de l''Ordre. Chaque bouchée était une révélation fromagère absolue. Vive les Tenracs !', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (106, 3, 'Fromage d''exception, tenders bénis, ambiance mystique au rendez-vous. Le Chevalier présidant a honoré la tradition avec brio.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2442, 13, 'La lampe à raclette ronronnait comme jamais. Fromage doré, tenders fondants. On ne pouvait rêver meilleure soirée entre Tenracs.', TO_DATE('2025-01-11', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (502, 10, 'Festin exceptionnel. Chaque plat était une ode à la raclette sacrée. Je suis fier et rassasié d''être membre de cet Ordre.', TO_DATE('2025-09-29', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1202, 15, 'Les tenders étaient d''une tendreté absolument transcendante. La sauce secrète restera gravée dans ma mémoire pour toujours.', TO_DATE('2024-10-29', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1092, 9, 'Raclette somptueuse, ambiance feutrée et solennelle. Le fromage coulait avec une grâce infinie. Honneur et saveur réunis.', TO_DATE('2026-02-17', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (42, 7, 'Soirée parfaite de bout en bout. La machine ronronnait, le fromage coulait, les tenders craquaient. L''Ordre est en grande forme.', TO_DATE('2024-08-19', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2248, 7, 'Le Grand Chancelier lui-même aurait applaudi. Qualité irréprochable, générosité exemplaire. Un repas de légende tenracienne.', TO_DATE('2025-09-08', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1692, 14, 'Les porte-spatules ont assuré avec maestria. Service impeccable, raclette parfaite. Cinq étoiles amplement mérités ce soir.', TO_DATE('2024-04-22', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2, 18, 'Fromage coulant, tenders croustillants, sauce divine. L''adresse secrète était idéale. Une soirée gravée dans les annales de l''Ordre.', TO_DATE('2026-01-14', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2516, 4, 'Dégustations sublimes. Les chevaliers ont honoré la tradition avec brio. On a raclé jusqu''à l''aube avec joie et dévotion.', TO_DATE('2024-11-24', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2903, 15, 'La nuit du fromage interminable portait bien son nom. Délicieuse, généreuse, mystérieuse. Magnifique souvenir de Tenrac.', TO_DATE('2025-12-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (865, 8, 'Communion parfaite autour du tender béni. Fromage coulant, ambiance chaleureuse. Un moment de grâce pure et fromagère.', TO_DATE('2024-09-14', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (158, 1, 'Les Frères de la Lampe Ardente ont brillé ce soir. Tout était parfait, du fromage à l''ambiance. Je reviendrai sans hésiter.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1589, 9, 'La croûte dorée méritait amplement son nom. Croustillante, généreuse, parfumée. Le Commandeur a validé chaque plat.', TO_DATE('2025-05-23', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (115, 8, 'Grand conclave réussi haut la main. Le fil fondu était interminable comme il se doit. Soirée inoubliable entre frères.', TO_DATE('2024-07-24', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2155, 8, 'Raclette traditionnelle sublimée par un fromage hors du commun. Les tenders dorés étaient à la hauteur des espérances.', TO_DATE('2024-07-05', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (963, 5, 'Impossible de trouver le moindre défaut ce soir. Tenders croustillants, fromage coulant, sauce maison irréprochable.', TO_DATE('2025-04-02', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2739, 9, 'Chaque bouchée de tender nappé de raclette était une prière silencieuse. L''Ordre sait encore recevoir. Chapeau bas.', TO_DATE('2026-03-03', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2688, 14, 'La sauce secrète de l''Ordre restera gravée dans ma mémoire. Associée aux tenders et au fromage, c''était divin.', TO_DATE('2024-05-25', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (994, 5, 'Organisation parfaite, fromage d''excellence, ambiance solennelle. La dignité du repas Tenrac était pleinement respectée.', TO_DATE('2024-12-05', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (164, 13, 'Le Maître d''entretien avait bien préparé la machine. Chauffe optimale, fromage parfait. On sent le soin apporté au rite.', TO_DATE('2025-08-25', 'YYYY-MM-DD'), 5);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1850, 14, 'Très bon repas dans l''ensemble. La raclette était généreuse. Quelques tenders un poil trop cuits mais rien de grave.', TO_DATE('2024-10-01', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1663, 15, 'Banquet de qualité, le fromage était excellent. Le service aurait pu être plus rapide mais l''ambiance compensait.', TO_DATE('2025-12-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1810, 21, 'Belle dégustation. La raclette manquait légèrement de sel mais les tenders étaient d''excellente facture ce soir.', TO_DATE('2024-11-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2886, 14, 'Bon repas, la lampe chauffait bien. J''aurais aimé un peu plus de variété dans les accompagnements proposés.', TO_DATE('2024-08-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2219, 21, 'Très bonne soirée. La raclette était fondante. Dommage que le repas ait été un peu court à mon goût personnel.', TO_DATE('2026-03-24', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (694, 24, 'Bon festin. Les tenders étaient savoureux. La raclette légèrement moins chaude qu''espéré mais très bonne quand même.', TO_DATE('2024-07-27', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1801, 13, 'Belle nuit fromagère. Fromage de qualité et tenders bien assaisonnés. Ambiance un peu moins mystérieuse qu''habituellement.', TO_DATE('2025-08-26', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2509, 25, 'Souper réussi. Raclette généreuse. Petit bémol sur l''organisation de la fin de soirée, un peu précipitée.', TO_DATE('2026-02-26', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2205, 24, 'Bonne communion autour du tender. Fromage coulant. On aurait apprécié un dessert à la hauteur du reste du repas.', TO_DATE('2024-10-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (433, 7, 'Festin bien réussi. Tenders croustillants et raclette fondante. Quelques minutes d''attente en trop entre les plats.', TO_DATE('2025-02-07', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2991, 14, 'Conclave plaisant. Léger déception sur la qualité du fromage ce soir mais bon repas dans l''ensemble.', TO_DATE('2024-07-19', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2813, 19, 'Bonne raclette traditionnelle. Le chevalier présidant a bien géré la soirée. Tenders dorés à la hauteur des espérances.', TO_DATE('2025-01-08', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1053, 24, 'Festin du tender réussi. Sauce secrète toujours mystérieuse. Manquait un peu de fromage à mon goût ce soir.', TO_DATE('2026-03-22', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1834, 11, 'Raclette des ombres bien mystérieuse. Fromage correct, tenders bien frits. Adresse secrète bien choisie ce soir.', TO_DATE('2025-11-14', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1975, 5, 'Banquet honorable. Petit manque d''originalité dans les plats proposés mais qualité maintenue. On ne se plaint pas.', TO_DATE('2026-02-14', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2648, 16, 'Bonne soirée tenracienne. Le fromage était coulant et les tenders moelleux. Un rien plus de sauce aurait été parfait.', TO_DATE('2024-04-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2442, 13, 'Repas de qualité servi avec soin. Le Chevalier présidant manquait un peu d''entrain mais le fromage compensait.', TO_DATE('2024-11-11', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (281, 1, 'La lampe chauffait bien ce soir. Raclette généreuse, tenders corrects. L''adresse secrète était un bon choix.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (299, 6, 'Très bon festin dans l''ensemble. Petit bémol sur la cuisson des tenders mais fromage impeccable et abondant.', TO_DATE('2024-04-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2049, 21, 'Soirée réussie. La confrérie a bien travaillé. Fromage fondant, tenders savoureux. Juste un peu moins d''attente.', TO_DATE('2026-03-05', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2636, 13, 'Belle réunion des frères de l''Ordre. Raclette de qualité, ambiance convenable. Les tenders auraient pu être plus chauds.', TO_DATE('2025-03-09', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1633, 15, 'Bon repas d''ensemble. Le fil fondu était long mais pas éternel. Fromage correct, tenders bien assaisonnés.', TO_DATE('2025-08-11', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (556, 11, 'Réunion agréable. La machine tournait bien. Fromage de bonne facture, tenders un peu secs mais savoureux.', TO_DATE('2024-10-02', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (5, 17, 'Festin plaisant. Les porte-spatules ont bien fait leur travail. Raclette généreuse, quelques maladresses à l''organisation.', TO_DATE('2025-01-01', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (174, 1, 'Bonne soirée malgré un léger retard au démarrage. Une fois lancée, la raclette était vraiment excellente.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2383, 12, 'Repas de bonne tenue. Le Commandeur présidait avec autorité. Fromage fondant, tenders corrects, ambiance solennelle.', TO_DATE('2025-04-06', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2323, 13, 'Soirée fromagère réussie. Seul bémol : le fromage manquait d''affinage. Mais les tenders rattrapaient largement.', TO_DATE('2025-01-21', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (292, 1, 'Conclave de qualité. Organisation un peu bancale mais résultat dans l''assiette très satisfaisant. Fromage top.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (970, 22, 'Très bon repas. La sauce secrète était particulièrement réussie ce soir. Fromage coulant, tenders bien frits.', TO_DATE('2025-05-29', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (680, 5, 'Belle réunion tenracienne. Le mystère de l''adresse bien préservé. Raclette généreuse, tenders savoureux. Bien joué.', TO_DATE('2025-02-18', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (589, 8, 'Bon festin de l''Ordre. Le fromage était de qualité. On aurait souhaité un peu plus de tenders mais c''était bon.', TO_DATE('2024-10-03', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2265, 22, 'Repas plaisant dans l''ensemble. La lampe à raclette chauffait bien. Tenders corrects, fromage abondant. Bonne soirée.', TO_DATE('2025-08-10', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1975, 5, 'Soirée convenable. Les frères de la lampe ardente ont assuré l''essentiel. Raclette fondante, tenders acceptables.', TO_DATE('2026-02-04', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2039, 11, 'Bonne réunion secrète. L''ambiance était au rendez-vous. Fromage coulant, tenders moelleux. Seul le dessert manquait.', TO_DATE('2024-06-29', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (243, 8, 'Repas de qualité. La machine était bien entretenue, ça se sentait. Fromage parfait, tenders légèrement trop salés.', TO_DATE('2024-04-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1095, 20, 'Festin réussi malgré quelques couacs organisationnels. La raclette a sauvé la soirée. Tenders corrects au final.', TO_DATE('2024-12-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1539, 15, 'Belle soirée Tenrac. Fromage généreux et coulant. Tenders un peu trop frits à mon goût mais savoureux quand même.', TO_DATE('2026-03-02', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1016, 19, 'Bon repas de l''Ordre. La Haute Dame présidait avec élégance. Fromage fondant, tenders moelleux, sauce agréable.', TO_DATE('2025-01-27', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (374, 5, 'Réunion agréable. L''adresse secrète était bien gardée. Raclette généreuse, tenders savoureux. Légère attente entre plats.', TO_DATE('2025-08-06', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2942, 8, 'Soirée bien organisée dans l''ensemble. Fromage de qualité, tenders corrects. L''Ordre maintient son niveau habituel.', TO_DATE('2024-06-29', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (289, 8, 'Festin honorable. Le Grand Chevalier présidait avec dignité. Raclette fondante, tenders croustillants. Bon repas.', TO_DATE('2024-10-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2423, 19, 'Bonne communion fromagère. Ambiance mystique présente. Raclette généreuse. Dommage que certains tenders fussent froids.', TO_DATE('2026-03-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2636, 13, 'Repas satisfaisant. La confrérie du coulant sacré a bien tenu ses promesses. Fromage coulant, tenders corrects.', TO_DATE('2024-12-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (863, 16, 'Belle soirée entre initiés. Le fil fondu était long. Fromage excellent. Petite déception sur la variété des plats.', TO_DATE('2026-03-24', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2036, 8, 'Bon festin tenracien. L''entretien de la machine se sentait dans la qualité de chauffe. Fromage parfait, tenders bons.', TO_DATE('2024-07-07', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (290, 3, 'Soirée de qualité. Les chevaliers ont honoré la tradition. Raclette généreuse, tenders moelleux. Ambiance solennelle.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (372, 17, 'Repas réussi. Le mystère de l''adresse bien préservé jusqu''au bout. Fromage fondant, tenders savoureux. Belle soirée.', TO_DATE('2025-02-25', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (544, 19, 'Bonne réunion de l''Ordre. Le Maître présidait avec sagesse. Fromage coulant, tenders croustillants. Légère attente.', TO_DATE('2024-12-16', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1403, 21, 'Festin de bonne tenue. Organisation correcte, fromage de qualité, tenders bien assaisonnés. On en redemande.', TO_DATE('2026-03-17', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1929, 12, 'Belle soirée fromagère. La lampe ardente bien réglée. Raclette généreuse, tenders corrects. Ambiance mystique réussie.', TO_DATE('2024-06-30', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1882, 8, 'Repas plaisant. Les porte-spatules efficaces. Fromage fondant et abondant. Tenders légèrement trop salés mais bons.', TO_DATE('2024-07-15', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (735, 22, 'Soirée agréable. Le conclave bien organisé. Raclette de qualité, tenders moelleux. Seul manque : plus de sauce.', TO_DATE('2025-05-05', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2974, 22, 'Bon festin entre frères. Fromage coulant, tenders savoureux. L''adresse secrète était particulièrement bien choisie.', TO_DATE('2025-03-22', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1512, 7, 'Réunion réussie. Le Commandeur présidait avec autorité. Raclette fondante, tenders croustillants. Petits couacs mineurs.', TO_DATE('2024-11-15', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (851, 9, 'Repas de qualité. La tradition Tenrac bien respectée. Fromage généreux, tenders corrects. On passe une bonne soirée.', TO_DATE('2026-01-09', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1024, 9, 'Belle soirée de l''Ordre. Fromage d''une belle fluidité. Tenders bien frits. Ambiance secrète et mystérieuse comme il faut.', TO_DATE('2025-08-03', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (532, 10, 'Festin satisfaisant. Les frères ont bien travaillé. Raclette généreuse, tenders savoureux. Légère improvisation finale.', TO_DATE('2025-08-25', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (364, 2, 'Bonne soirée tenracienne. Fromage de qualité, tenders moelleux. L''organisation aurait pu être un peu plus carrée.', TO_DATE('2025-04-27', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (944, 21, 'Repas réussi dans l''ensemble. La sauce secrète était excellente. Fromage coulant, tenders corrects. Belle soirée.', TO_DATE('2025-11-12', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2998, 24, 'Soirée plaisante. Le Grand Maître aurait approuvé. Raclette généreuse, tenders bien cuits. Petit bémol sur l''attente.', TO_DATE('2024-08-25', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2213, 6, 'Bon festin de la confrérie. Fromage fondant, tenders croustillants. Organisation légèrement perfectible mais bon repas.', TO_DATE('2024-08-30', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2331, 23, 'Belle réunion secrète. L''adresse était bien gardée. Raclette généreuse, tenders corrects. Ambiance mystique agréable.', TO_DATE('2026-01-29', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1092, 9, 'Très bon repas dans l''ensemble. La raclette était généreuse. Quelques tenders un poil trop cuits mais rien de grave.', TO_DATE('2026-03-01', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1824, 5, 'Banquet de qualité, le fromage était excellent. Le service aurait pu être plus rapide mais l''ambiance compensait.', TO_DATE('2026-03-14', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1692, 14, 'Belle dégustation. La raclette manquait légèrement de sel mais les tenders étaient d''excellente facture ce soir.', TO_DATE('2024-07-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (93, 3, 'Bon repas, la lampe chauffait bien. J''aurais aimé un peu plus de variété dans les accompagnements proposés.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1711, 25, 'Très bonne soirée. La raclette était fondante. Dommage que le repas ait été un peu court à mon goût personnel.', TO_DATE('2024-09-19', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (146, 1, 'Bon festin. Les tenders étaient savoureux. La raclette légèrement moins chaude qu''espéré mais très bonne quand même.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (841, 13, 'Belle nuit fromagère. Fromage de qualité et tenders bien assaisonnés. Ambiance un peu moins mystérieuse qu''habituellement.', TO_DATE('2025-11-25', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (548, 5, 'Souper réussi. Raclette généreuse. Petit bémol sur l''organisation de la fin de soirée, un peu précipitée.', TO_DATE('2025-05-22', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2252, 25, 'Bonne communion autour du tender. Fromage coulant. On aurait apprécié un dessert à la hauteur du reste du repas.', TO_DATE('2025-05-19', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2102, 12, 'Festin bien réussi. Tenders croustillants et raclette fondante. Quelques minutes d''attente en trop entre les plats.', TO_DATE('2024-08-31', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (223, 11, 'Conclave plaisant. Léger déception sur la qualité du fromage ce soir mais bon repas dans l''ensemble.', TO_DATE('2025-11-19', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1722, 21, 'Bonne raclette traditionnelle. Le chevalier présidant a bien géré la soirée. Tenders dorés à la hauteur des espérances.', TO_DATE('2026-03-23', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (262, 3, 'Festin du tender réussi. Sauce secrète toujours mystérieuse. Manquait un peu de fromage à mon goût ce soir.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1480, 18, 'Raclette des ombres bien mystérieuse. Fromage correct, tenders bien frits. Adresse secrète bien choisie ce soir.', TO_DATE('2025-10-16', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (402, 11, 'Banquet honorable. Petit manque d''originalité dans les plats proposés mais qualité maintenue. On ne se plaint pas.', TO_DATE('2025-12-11', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (171, 1, 'Bonne soirée tenracienne. Le fromage était coulant et les tenders moelleux. Un rien plus de sauce aurait été parfait.', TO_DATE('2024-01-26', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (768, 24, 'Repas de qualité servi avec soin. Le Chevalier présidant manquait un peu d''entrain mais le fromage compensait.', TO_DATE('2026-01-29', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (468, 19, 'La lampe chauffait bien ce soir. Raclette généreuse, tenders corrects. L''adresse secrète était un bon choix.', TO_DATE('2024-10-05', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2790, 22, 'Très bon festin dans l''ensemble. Petit bémol sur la cuisson des tenders mais fromage impeccable et abondant.', TO_DATE('2025-08-03', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (659, 9, 'Soirée réussie. La confrérie a bien travaillé. Fromage fondant, tenders savoureux. Juste un peu moins d''attente.', TO_DATE('2025-07-12', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1792, 11, 'Belle réunion des frères de l''Ordre. Raclette de qualité, ambiance convenable. Les tenders auraient pu être plus chauds.', TO_DATE('2026-01-21', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (176, 3, 'Bon repas d''ensemble. Le fil fondu était long mais pas éternel. Fromage correct, tenders bien assaisonnés.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1936, 15, 'Réunion agréable. La machine tournait bien. Fromage de bonne facture, tenders un peu secs mais savoureux.', TO_DATE('2025-12-30', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (797, 4, 'Festin plaisant. Les porte-spatules ont bien fait leur travail. Raclette généreuse, quelques maladresses à l''organisation.', TO_DATE('2026-01-11', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (368, 11, 'Bonne soirée malgré un léger retard au démarrage. Une fois lancée, la raclette était vraiment excellente.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1980, 10, 'Repas de bonne tenue. Le Commandeur présidait avec autorité. Fromage fondant, tenders corrects, ambiance solennelle.', TO_DATE('2025-07-15', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (102, 11, 'Soirée fromagère réussie. Seul bémol : le fromage manquait d''affinage. Mais les tenders rattrapaient largement.', TO_DATE('2025-08-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (559, 9, 'Conclave de qualité. Organisation un peu bancale mais résultat dans l''assiette très satisfaisant. Fromage top.', TO_DATE('2026-02-15', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2639, 8, 'Très bon repas. La sauce secrète était particulièrement réussie ce soir. Fromage coulant, tenders bien frits.', TO_DATE('2024-03-06', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1848, 23, 'Belle réunion tenracienne. Le mystère de l''adresse bien préservé. Raclette généreuse, tenders savoureux. Bien joué.', TO_DATE('2026-03-01', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (11, 14, 'Bon festin de l''Ordre. Le fromage était de qualité. On aurait souhaité un peu plus de tenders mais c''était bon.', TO_DATE('2024-04-22', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (111, 6, 'Repas plaisant dans l''ensemble. La lampe à raclette chauffait bien. Tenders corrects, fromage abondant. Bonne soirée.', TO_DATE('2024-03-28', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2725, 2, 'Soirée convenable. Les frères de la lampe ardente ont assuré l''essentiel. Raclette fondante, tenders acceptables.', TO_DATE('2025-03-10', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1953, 11, 'Bonne réunion secrète. L''ambiance était au rendez-vous. Fromage coulant, tenders moelleux. Seul le dessert manquait.', TO_DATE('2024-12-20', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (726, 6, 'Repas de qualité. La machine était bien entretenue, ça se sentait. Fromage parfait, tenders légèrement trop salés.', TO_DATE('2024-09-25', 'YYYY-MM-DD'), 4);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1614, 5, 'Repas correct sans être mémorable. La raclette était un peu froide. Les tenders compensaient heureusement la situation.', TO_DATE('2025-02-22', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1808, 20, 'Soirée moyenne. La lampe semblait fatiguée. Fromage pas assez coulant, tenders corrects. On a vu mieux par le passé.', TO_DATE('2026-03-18', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (849, 15, 'Cène décevante. L''ambiance mystique n''était pas vraiment au rendez-vous. La raclette était banale ce soir.', TO_DATE('2024-11-18', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1596, 20, 'Festin moyen. Les porte-spatules manquaient d''entrain. La raclette correcte mais sans éclat particulier.', TO_DATE('2026-03-17', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2061, 23, 'Nuit fromagère sans grand relief. Fromage acceptable mais pas exceptionnel. Les tenders étaient trop secs.', TO_DATE('2026-01-27', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (249, 3, 'Souper passable. Le gril mystique n''était pas très inspiré ce soir. Raclette correcte, tenders ordinaires.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2185, 21, 'Communion tendue. Quelques désaccords sur la cuisson plombaient l''ambiance. Fromage correct, soirée en demi-teinte.', TO_DATE('2026-03-21', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1633, 15, 'La croûte n''était pas aussi dorée qu''annoncé. Repas honnête mais sans surprise. Ambiance un peu plate.', TO_DATE('2025-07-12', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (330, 10, 'Conclave moyen. Le fil fondu s''est cassé trop vite. Organisation perfectible. La raclette sauvait les meubles.', TO_DATE('2025-03-08', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (266, 17, 'Raclette trop traditionnelle justement. Manque d''originalité flagrant. On attendait plus de créativité ce soir.', TO_DATE('2024-05-16', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1980, 10, 'Tender correct mais sauce moins secrète que d''habitude. L''impression d''avoir déjà goûté ça. Repas sans surprise.', TO_DATE('2025-11-11', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (248, 8, 'Raclette des ombres trop éclairée. Manque de mystère et de fromage. Les tenders étaient trop frits.', TO_DATE('2024-03-25', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1698, 2, 'Banquet trop long et pas assez garni. On a attendu entre chaque plat. Raclette correcte, organisation moyenne.', TO_DATE('2024-06-27', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1764, 24, 'Dégustation ordinaire. Les chevaliers semblaient fatigués. Fromage moyen, tenders acceptables. Rien de transcendant.', TO_DATE('2026-03-23', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (974, 23, 'Repas honnête. Rien d''extraordinaire, rien de catastrophique. Le fromage fondait, les tenders étaient là. Voilà.', TO_DATE('2026-01-27', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2121, 5, 'Soirée sans relief. La machine tournait, le fromage fondait, les tenders cuisaient. Mais la magie n''était pas là.', TO_DATE('2025-08-04', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (17, 25, 'Repas acceptable. Le Chevalier présidant manquait de conviction. Fromage moyen, tenders corrects. Bof.', TO_DATE('2024-11-23', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1040, 2, 'Festin ordinaire. On s''attendait à mieux de la part de cette confrérie. Fromage pas terrible, tenders passables.', TO_DATE('2025-04-19', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2158, 14, 'Réunion sans grande surprise. Tout était dans la moyenne. Raclette correcte, tenders acceptables. Ni bien ni mal.', TO_DATE('2024-06-29', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2143, 5, 'Soirée tenracienne quelconque. Le fil fondu manquait d''élasticité. Fromage correct, tenders un peu fades.', TO_DATE('2025-03-31', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (390, 21, 'Repas moyen. La lampe chauffait irrégulièrement. Fromage parfois coulant, parfois non. Tenders corrects.', TO_DATE('2025-05-26', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (229, 8, 'Festin sans éclat. Le Grand Chevalier semblait distrait. Raclette ordinaire, tenders sans grand caractère.', TO_DATE('2024-09-03', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2018, 15, 'Soirée correcte mais sans plus. L''adresse secrète était bien mais le repas n''était pas à la hauteur du lieu.', TO_DATE('2024-10-31', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2478, 11, 'Repas passable. Le mystère de l''adresse était réussi mais le fromage ne l''était pas vraiment. Tenders corrects.', TO_DATE('2026-03-20', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1692, 14, 'Conclave honnête. Organisation correcte, fromage moyen, tenders acceptables. On attendait davantage de cette réunion.', TO_DATE('2024-08-17', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2355, 21, 'Réunion sans grand intérêt gastronomique. Fromage correct, tenders passables. L''ambiance était trop sage.', TO_DATE('2025-11-22', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (825, 5, 'Festin de milieu de tableau. Fromage fondant mais fade. Tenders corrects mais sans saveur particulière.', TO_DATE('2026-03-25', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (580, 4, 'Soirée mitigée. La raclette démarrait bien puis perdait en qualité. Tenders inégaux. Ambiance correcte.', TO_DATE('2026-01-30', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1589, 9, 'Repas sans surprise. Tout était prévisible. Fromage fondu, tenders frits. La tradition sans l''inspiration.', TO_DATE('2025-03-07', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1596, 20, 'Festin convenable. Le Commandeur présidait avec sérieux mais le fromage manquait de caractère. Tenders bons.', TO_DATE('2026-03-14', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (392, 2, 'Soirée dans la moyenne. Rien à reprocher vraiment, rien à féliciter vraiment. La raclette était là c''est tout.', TO_DATE('2026-02-06', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (142, 8, 'Repas acceptable. L''organisation était correcte. Fromage de qualité moyenne, tenders sans grand relief.', TO_DATE('2024-10-12', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2650, 19, 'Réunion ordinaire. Le fil fondu manquait d''enthousiasme. Fromage correct, tenders acceptables. Soirée oubliable.', TO_DATE('2024-05-20', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1810, 21, 'Festin passable. La machine tournait mais sans conviction. Fromage moyen, tenders corrects. Ni chaud ni froid.', TO_DATE('2024-06-21', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (796, 2, 'Soirée tenracienne moyenne. On sentait le manque de préparation. Fromage correct, tenders passables.', TO_DATE('2024-06-24', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (103, 1, 'Repas honnête mais sans âme. La tradition était respectée mécaniquement. Fromage coulant, tenders cuits. C''est tout.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2087, 5, 'Conclave sans relief. Ambiance secrète bien gardée mais repas décevant. Fromage ordinaire, tenders moyens.', TO_DATE('2026-03-11', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2864, 13, 'Soirée correcte sans plus. Le Grand Maître aurait sans doute mieux fait. Fromage passable, tenders corrects.', TO_DATE('2024-11-05', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1720, 15, 'Repas dans la norme tenracienne. Rien d''exceptionnel. Fromage fondu, tenders frits. Le minimum syndical.', TO_DATE('2025-11-04', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1908, 17, 'Festin quelconque. La sauce secrète semblait moins secrète. Fromage correct, tenders sans caractère particulier.', TO_DATE('2025-01-09', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1584, 8, 'Soirée moyenne. La lampe chauffait bien au moins. Fromage de qualité ordinaire. Tenders corrects, ambiance plate.', TO_DATE('2024-06-23', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (74, 6, 'Repas passable. Le Chevalier présidant manquait d''entrain. Fromage moyen, tenders acceptables. Bof dans l''ensemble.', TO_DATE('2024-10-27', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1126, 8, 'Réunion correcte. Organisation sans failles mais sans inspiration. Fromage correct, tenders passables. Correct.', TO_DATE('2024-06-15', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (865, 8, 'Festin de milieu de gamme. Les attentes étaient hautes, le résultat moyen. Fromage fond, tenders frits. Voilà.', TO_DATE('2024-09-08', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (567, 19, 'Soirée tenracienne sans grand éclat. La tradition était là mais pas la passion. Fromage moyen, tenders corrects.', TO_DATE('2024-10-03', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1507, 4, 'Repas correct sans être mémorable. La raclette était un peu froide. Les tenders compensaient heureusement la situation.', TO_DATE('2024-08-17', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (215, 3, 'Soirée moyenne. La lampe semblait fatiguée. Fromage pas assez coulant, tenders corrects. On a vu mieux par le passé.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1893, 4, 'Cène décevante. L''ambiance mystique n''était pas vraiment au rendez-vous. La raclette était banale ce soir.', TO_DATE('2025-01-18', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (567, 16, 'Festin moyen. Les porte-spatules manquaient d''entrain. La raclette correcte mais sans éclat particulier.', TO_DATE('2025-11-17', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2376, 4, 'Nuit fromagère sans grand relief. Fromage acceptable mais pas exceptionnel. Les tenders étaient trop secs.', TO_DATE('2024-10-21', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (267, 3, 'Souper passable. Le gril mystique n''était pas très inspiré ce soir. Raclette correcte, tenders ordinaires.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (445, 16, 'Communion tendue. Quelques désaccords sur la cuisson plombaient l''ambiance. Fromage correct, soirée en demi-teinte.', TO_DATE('2024-08-06', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1305, 21, 'La croûte n''était pas aussi dorée qu''annoncé. Repas honnête mais sans surprise. Ambiance un peu plate.', TO_DATE('2026-03-13', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2331, 23, 'Conclave moyen. Le fil fondu s''est cassé trop vite. Organisation perfectible. La raclette sauvait les meubles.', TO_DATE('2026-02-16', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (825, 5, 'Raclette trop traditionnelle justement. Manque d''originalité flagrant. On attendait plus de créativité ce soir.', TO_DATE('2026-02-17', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (990, 15, 'Tender correct mais sauce moins secrète que d''habitude. L''impression d''avoir déjà goûté ça. Repas sans surprise.', TO_DATE('2025-09-01', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2235, 8, 'Raclette des ombres trop éclairée. Manque de mystère et de fromage. Les tenders étaient trop frits.', TO_DATE('2024-11-08', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2688, 14, 'Banquet trop long et pas assez garni. On a attendu entre chaque plat. Raclette correcte, organisation moyenne.', TO_DATE('2024-06-13', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2297, 24, 'Dégustation ordinaire. Les chevaliers semblaient fatigués. Fromage moyen, tenders acceptables. Rien de transcendant.', TO_DATE('2024-03-20', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2, 18, 'Repas honnête. Rien d''extraordinaire, rien de catastrophique. Le fromage fondait, les tenders étaient là. Voilà.', TO_DATE('2025-11-24', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2155, 8, 'Soirée sans relief. La machine tournait, le fromage fondait, les tenders cuisaient. Mais la magie n''était pas là.', TO_DATE('2024-06-26', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (791, 10, 'Repas acceptable. Le Chevalier présidant manquait de conviction. Fromage moyen, tenders corrects. Bof.', TO_DATE('2025-07-08', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (298, 7, 'Festin ordinaire. On s''attendait à mieux de la part de cette confrérie. Fromage pas terrible, tenders passables.', TO_DATE('2025-05-05', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2143, 5, 'Réunion sans grande surprise. Tout était dans la moyenne. Raclette correcte, tenders acceptables. Ni bien ni mal.', TO_DATE('2025-08-12', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2739, 9, 'Soirée tenracienne quelconque. Le fil fondu manquait d''élasticité. Fromage correct, tenders un peu fades.', TO_DATE('2025-12-11', 'YYYY-MM-DD'), 3);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (310, 21, 'Soirée décevante. La lampe tombait en panne toutes les dix minutes. Fromage à peine fondu, tenders froids.', TO_DATE('2025-12-08', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (140, 24, 'Cène ratée. Le fromage était trop épais et mal cuit. Les tenders semblaient réchauffés. Ambiance absente.', TO_DATE('2026-02-02', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2864, 13, 'Festin des porte-spatules décevant. Quantités insuffisantes pour tous. Fromage rare, tenders comptés.', TO_DATE('2025-01-24', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (287, 20, 'Nuit fromagère cauchemardesque. Fromage dur, tenders caoutchouteux. Soirée à oublier rapidement.', TO_DATE('2026-01-30', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1850, 14, 'Souper raté. Le gril mystique a rendu l''âme en plein repas. Froid, ambiance glaciale. Très décevant.', TO_DATE('2024-10-04', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (857, 19, 'Communion avortée. La machine en panne. Fromage tiède, ambiance nulle. Expérience à ne pas renouveler.', TO_DATE('2024-08-25', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (276, 3, 'La croûte était carbonisée. Tenders brûlés, fromage caoutchouteux. Le Commandeur a quitté tôt la table.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2886, 14, 'Grand conclave raté. Fromage de mauvaise qualité. Tenders trop frits. Grande déception pour l''Ordre.', TO_DATE('2024-08-29', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (990, 15, 'Repas bâclé. On sentait le manque de préparation. Fromage insipide, tenders trop cuits. Vraiment décevant.', TO_DATE('2025-03-27', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1558, 16, 'Soirée ratée. La lampe chauffait trop fort. Fromage brûlé, tenders carbonisés. L''Ordre mérite bien mieux.', TO_DATE('2026-03-14', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (56, 1, 'Festin décevant. Les chevaliers n''avaient visiblement pas le cœur à l''ouvrage. Fromage médiocre, tenders secs.', TO_DATE('2024-01-26', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (241, 3, 'Réunion bâclée. L''adresse secrète était bien mais le repas ne l''était pas. Fromage dur, tenders insipides.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (797, 17, 'Repas raté. Organisation chaotique. Fromage trop froid, tenders trop secs. Une honte pour la tradition Tenrac.', TO_DATE('2025-06-28', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (485, 8, 'Soirée décevante. Le mystère de l''adresse bien gardé mais le fromage oublié. Tenders trop salés. Décevant.', TO_DATE('2024-08-26', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (248, 8, 'Conclave raté. Le Chevalier présidant était absent d''esprit. Fromage médiocre, tenders mal cuits. Dommage.', TO_DATE('2024-06-30', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2863, 22, 'Festin en dessous de tout. La machine n''était pas entretenue. Fromage collant, tenders froids. Inadmissible.', TO_DATE('2024-05-25', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1028, 24, 'Soirée gâchée. Le fromage n''était pas de qualité. Les tenders semblaient d''une autre semaine. Décevant.', TO_DATE('2026-01-23', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (556, 11, 'Repas raté. La sauce secrète était de la mayonnaise industrielle. Fromage médiocre, tenders passables.', TO_DATE('2024-10-16', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (148, 20, 'Réunion décevante. Organisation défaillante, fromage insipide, tenders trop cuits. L''Ordre peut faire mieux.', TO_DATE('2026-01-26', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2437, 7, 'Festin bâclé. On attendait un repas tenracien, on a eu une raclette de cantine. Fromage triste, tenders secs.', TO_DATE('2025-06-22', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (812, 19, 'Soirée ratée. La lampe chauffait irrégulièrement. Fromage brûlé d''un côté, froid de l''autre. Tenders ordinaires.', TO_DATE('2024-06-08', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (251, 24, 'Repas décevant. Le Grand Chevalier semblait distrait. Fromage sans goût, tenders caoutchouteux. Déception.', TO_DATE('2024-06-16', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2115, 8, 'Conclave raté. Le fil fondu ne s''est pas formé. Fromage trop vieux, tenders mal frits. Soirée à oublier.', TO_DATE('2024-11-14', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (25, 1, 'Festin médiocre. Les porte-spatules n''ont pas assuré. Fromage dur, tenders froids. On attendait tellement mieux.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2870, 13, 'Soirée en dessous des attentes. Fromage de supermarché, tenders réchauffés. La tradition bafouée ce soir.', TO_DATE('2025-07-16', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2991, 14, 'Repas raté. La machine n''avait pas été entretenue depuis longtemps. Fromage collant, tenders insipides.', TO_DATE('2024-09-24', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (849, 15, 'Réunion décevante. L''ambiance mystique inexistante. Fromage médiocre, tenders trop secs. Retour à la base.', TO_DATE('2024-10-23', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2928, 16, 'Festin bâclé. On sentait la précipitation. Fromage pas fondu, tenders trop cuits. Une soirée à oublier.', TO_DATE('2025-08-10', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1882, 8, 'Soirée ratée. Désorganisation totale. Fromage arrivé froid, tenders arrivés après. Aucune cohérence.', TO_DATE('2024-07-19', 'YYYY-MM-DD'), 2);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (216, 9, 'Repas décevant. Le Commandeur absent. Fromage sans caractère, tenders insipides. L''Ordre en berne ce soir.', TO_DATE('2025-07-31', 'YYYY-MM-DD'), 2);
