INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1882, 8, 'Raclette immanquable. Fromage froid, tenders crus. La lampe ne chauffait pas. Honte à l''organisateur.', TO_DATE('2024-08-27', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (216, 9, 'Festin catastrophique. Tenders réchauffés. La sauce secrète était du ketchup industriel. Inadmissible.', TO_DATE('2025-08-11', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (75, 1, 'Raclette des ombres : les ombres ont tout mangé avant nous. Portions minuscules, fromage insipide.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (735, 22, 'Banquet indigne. Fromage avarié, tenders oubliés dans la friteuse, machine en panne. Scandale absolu.', TO_DATE('2025-08-19', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2991, 14, 'Pire dégustation de ma vie Tenrac. Tout froid, rien prêt. Les chevaliers étaient aussi perdus que moi.', TO_DATE('2024-06-16', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (82, 18, 'Lampe ardente n''ardait pas. Fromage industriel, tenders congelés non décongelés. Scandale absolu.', TO_DATE('2026-02-11', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (11, 8, 'La cène du coulant éternel : rien n''a coulé. Fromage bloc, tenders caoutchouc. Je demande réparation.', TO_DATE('2024-05-24', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (73, 3, 'Les porte-spatules ont porté des spatules inutiles. Rien à racler, rien à manger. Désastre total.', TO_DATE('2024-03-13', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (247, 6, 'Honte à l''organisateur. Fromage avarié, machine non entretenue, tenders brûlés. Inadmissible.', TO_DATE('2024-05-18', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (197, 8, 'Soirée catastrophique. Le Grand Maître serait consterné. Fromage froid, tenders crus, machine en panne.', TO_DATE('2024-05-26', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (691, 22, 'Désastre total. Rien n''était prêt à l''heure. Fromage dur, tenders caoutchouteux. Soirée honteuse.', TO_DATE('2025-05-21', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (224, 5, 'Repas honteux. La sauce secrète avait tourné. Fromage dur, tenders brûlés. Une trahison envers l''Ordre.', TO_DATE('2026-02-25', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (190, 13, 'Catastrophe tenracienne. Fromage de mauvaise qualité, tenders oubliés, lampe en panne. Scandale.', TO_DATE('2024-12-31', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (963, 5, 'Soirée scandaleuse. Organisation nulle, fromage infect, tenders brûlés. Je quitte temporairement l''Ordre.', TO_DATE('2025-05-23', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1651, 16, 'Le pire festin que j''aie vécu. Fromage froid et dur, tenders carbonisés, sauce inexistante. Inadmissible.', TO_DATE('2026-03-22', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2688, 8, 'Honte absolue. La machine n''avait pas été entretenue. Fromage collé, tenders brûlés. Zéro pointé.', TO_DATE('2024-02-20', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (82, 18, 'Désastre complet. Le Chevalier présidant avait oublié le fromage. Tenders seuls ne font pas une raclette.', TO_DATE('2025-09-29', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (169, 17, 'Repas catastrophique. Fromage acheté en urgence et de piètre qualité. Tenders d''une autre semaine. Honte.', TO_DATE('2024-06-15', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (694, 24, 'Soirée honteuse. Rien de ce qui fait un repas Tenrac n''était là. Fromage absent, tenders absents. Rien.', TO_DATE('2024-03-14', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2697, 9, 'La pire expérience tenracienne de ma carrière. Fromage dur, tenders brûlés, lampe en panne. Inadmissible.', TO_DATE('2025-02-10', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1391, 12, 'Raclette immanquable. Fromage froid, tenders crus. La lampe ne chauffait pas. Honte à l''organisateur.', TO_DATE('2025-08-10', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (450, 20, 'Festin catastrophique. Tenders réchauffés. La sauce secrète était du ketchup industriel. Inadmissible.', TO_DATE('2024-04-30', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (307, 24, 'Raclette des ombres : les ombres ont tout mangé avant nous. Portions minuscules, fromage insipide.', TO_DATE('2026-03-16', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (248, 8, 'Banquet indigne. Fromage avarié, tenders oubliés dans la friteuse, machine en panne. Scandale absolu.', TO_DATE('2024-03-02', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (1751, 11, 'Pire dégustation de ma vie Tenrac. Tout froid, rien prêt. Les chevaliers étaient aussi perdus que moi.', TO_DATE('2026-01-21', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (45, 1, 'Lampe ardente n''ardait pas. Fromage industriel, tenders congelés non décongelés. Scandale absolu.', TO_DATE('2024-01-26', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (330, 10, 'La cène du coulant éternel : rien n''a coulé. Fromage bloc, tenders caoutchouc. Je demande réparation.', TO_DATE('2025-05-21', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2945, 5, 'Les porte-spatules ont porté des spatules inutiles. Rien à racler, rien à manger. Désastre total.', TO_DATE('2025-08-10', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2991, 24, 'Honte à l''organisateur. Fromage avarié, machine non entretenue, tenders brûlés. Inadmissible.', TO_DATE('2024-04-26', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (217, 1, 'Soirée catastrophique. Le Grand Maître serait consterné. Fromage froid, tenders crus, machine en panne.', TO_DATE('2025-10-28', 'YYYY-MM-DD'), 1);
INSERT INTO Note (idTenrac, idRepas, avis, date_, note) VALUES (2788, 4, 'Désastre total. Rien n''était prêt à l''heure. Fromage dur, tenders caoutchouteux. Soirée honteuse.', TO_DATE('2025-03-14', 'YYYY-MM-DD'), 1);
